"use client"

import React, { useCallback, useState } from "react"
import { Cause, Exit, Option } from "effect"
import { useAtomValue } from "@effect-atom/atom-react"
import { keypairAtom } from "@/atoms/falcon"
import { networkAtom } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import { StarknetService } from "@/services/StarknetService"
import { FalconSigner } from "@/services/FalconSigner"
import type { ContractAddress } from "@/services/types"
import type { ManagedRuntime } from "effect"
import type { FalconService } from "@/services/FalconService"

interface SendTransactionProps {
  readonly deployedAddress: ContractAddress
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly deployRuntime: ManagedRuntime.ManagedRuntime<FalconService | StarknetService, any>
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly falconRuntime: ManagedRuntime.ManagedRuntime<FalconService, any>
}

export function SendTransaction({
  deployedAddress,
  deployRuntime,
  falconRuntime,
}: SendTransactionProps): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const [recipient, setRecipient] = useState(deployedAddress as string)
  const [amount, setAmount] = useState("0.001")
  const [sending, setSending] = useState(false)
  const [result, setResult] = useState<{ txHash: string } | null>(null)
  const [error, setError] = useState<string | null>(null)

  const handleSend = useCallback(async () => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    if (!kp) return

    setSending(true)
    setError(null)
    setResult(null)

    const signer = new FalconSigner(kp.secretKey, kp.publicKeyNtt, falconRuntime)
    const amountWei = BigInt(Math.floor(parseFloat(amount) * 1e18))

    const exit = await deployRuntime.runPromiseExit(
      StarknetService.sendTransaction(
        deployedAddress as string,
        signer,
        recipient,
        amountWei,
      ),
    )

    setSending(false)

    if (Exit.isSuccess(exit)) {
      setResult({ txHash: exit.value.txHash })
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      setError(
        Option.match(errOpt, {
          onNone: () => "Transaction failed",
          onSome: (e) => e.message,
        }),
      )
    }
  }, [keypair, deployedAddress, recipient, amount, deployRuntime, falconRuntime])

  return (
    <div className="mt-6 rounded-xl border border-falcon-muted/20 bg-falcon-surface p-5">
      <h3 className="font-semibold text-falcon-text">Test Your Falcon Account</h3>
      <p className="mt-1 text-sm text-falcon-muted">
        Send STRK using your post-quantum account.
      </p>

      <div className="mt-4 space-y-3">
        <div>
          <label htmlFor="tx-recipient" className="block text-sm font-medium text-falcon-text">
            Recipient
          </label>
          <input
            id="tx-recipient"
            type="text"
            value={recipient}
            onChange={(e) => setRecipient(e.target.value)}
            className="mt-1 w-full rounded-lg border border-falcon-muted/30 bg-falcon-bg px-4 py-2 font-mono text-sm text-falcon-text focus:outline-none focus:ring-2 focus:ring-falcon-primary"
          />
        </div>

        <div>
          <label htmlFor="tx-amount" className="block text-sm font-medium text-falcon-text">
            Amount (STRK)
          </label>
          <input
            id="tx-amount"
            type="text"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            className="mt-1 w-full rounded-lg border border-falcon-muted/30 bg-falcon-bg px-4 py-2 font-mono text-sm text-falcon-text focus:outline-none focus:ring-2 focus:ring-falcon-primary"
          />
        </div>

        <button
          onClick={handleSend}
          disabled={sending || !Option.isSome(keypair)}
          className="rounded-lg bg-falcon-accent px-6 py-2.5 text-sm font-semibold text-falcon-text hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
        >
          {sending ? "Sending..." : "Send STRK"}
        </button>
      </div>

      {result !== null && (
        <div className="mt-4 rounded-xl border border-falcon-success/30 bg-falcon-success/10 p-4">
          <p className="font-semibold text-falcon-success">Transaction Confirmed</p>
          <p className="mt-1 break-all font-mono text-xs text-falcon-text">
            Tx: {result.txHash}
          </p>
          {networkConfig.explorerBaseUrl && (
            <a
              href={`${networkConfig.explorerBaseUrl}/tx/${result.txHash}`}
              target="_blank"
              rel="noreferrer noopener"
              className="mt-2 inline-block text-sm text-falcon-accent hover:underline"
            >
              View on Voyager
            </a>
          )}
        </div>
      )}

      {error !== null && (
        <div className="mt-4 rounded-xl border border-falcon-error/30 bg-falcon-error/10 p-4">
          <p className="text-sm text-falcon-error">{error}</p>
        </div>
      )}
    </div>
  )
}

import { Effect, Option, Schema } from "effect"
import type { SignerInterface } from "starknet"
import { FalconService } from "@/services/FalconService"
import { StarknetService } from "@/services/StarknetService"
import { InsufficientFundsError } from "@/services/errors"
import type {
  ContractAddress,
  FalconKeypair,
  PackedPublicKey,
} from "@/services/types"

const FALCON_PUBLIC_KEY_LENGTH = 512
const FALCON_MODULUS = 12289

export class InvalidPrivateKeyError extends Schema.TaggedError<InvalidPrivateKeyError>()(
  "InvalidPrivateKeyError",
  { message: Schema.String },
) {}

export class InvalidPublicKeyNttError extends Schema.TaggedError<InvalidPublicKeyNttError>()(
  "InvalidPublicKeyNttError",
  { message: Schema.String },
) {}

export interface PreparedAccountDeploy {
  readonly privateKey: string
  readonly keypair: FalconKeypair
  readonly packedPublicKey: PackedPublicKey
  readonly address: ContractAddress
  readonly salt: string
}

export interface DeployAccountInput {
  readonly address: ContractAddress
  readonly packedPublicKey: PackedPublicKey
  readonly signer: SignerInterface
  readonly salt: string
  readonly requiredBalance: bigint
}

export const validateHexPrivateKey = Effect.fn(
  "AccountDeployPipeline.validateHexPrivateKey",
)((privateKey: string) =>
  Effect.try({
    try: () => {
      const trimmed = privateKey.trim()
      const normalized = trimmed.toLowerCase()

      if (!normalized.startsWith("0x")) {
        throw new Error("Private key must be 0x-prefixed")
      }

      const hexBody = normalized.slice(2)
      if (hexBody.length === 0 || hexBody.length > 64) {
        throw new Error("Private key must be between 1 and 32 bytes hex")
      }

      if (!/^[0-9a-f]+$/u.test(hexBody)) {
        throw new Error("Private key contains non-hex characters")
      }

      // Pad to 32 bytes for consistency (Starknet private keys may be shorter)
      return `0x${hexBody.padStart(64, "0")}`
    },
    catch: (error) =>
      new InvalidPrivateKeyError({
        message: String(error),
      }),
  }),
)

export const toUint16PublicKeyNtt = Effect.fn(
  "AccountDeployPipeline.toUint16PublicKeyNtt",
)((publicKeyNtt: Int32Array) =>
  Effect.try({
    try: () => {
      if (publicKeyNtt.length !== FALCON_PUBLIC_KEY_LENGTH) {
        throw new Error(
          `publicKeyNtt must have ${FALCON_PUBLIC_KEY_LENGTH} coefficients`,
        )
      }

      const packed = new Uint16Array(FALCON_PUBLIC_KEY_LENGTH)
      for (let i = 0; i < publicKeyNtt.length; i += 1) {
        const coeff = publicKeyNtt[i]
        if (coeff < 0 || coeff >= FALCON_MODULUS) {
          throw new Error(`publicKeyNtt coefficient out of range at index ${i}`)
        }
        packed[i] = coeff
      }

      return packed
    },
    catch: (error) =>
      new InvalidPublicKeyNttError({
        message: String(error),
      }),
  }),
)

interface PrepareAccountDeployInput {
  readonly privateKey: string
  readonly existingKeypair: Option.Option<FalconKeypair>
}

export const prepareAccountDeployEffect = Effect.fn(
  "AccountDeployPipeline.prepareAccountDeployEffect",
)(function* ({ privateKey, existingKeypair }: PrepareAccountDeployInput) {
  const normalizedPrivateKey = yield* validateHexPrivateKey(privateKey)

  const keypair = yield* Option.match(existingKeypair, {
    onNone: () => FalconService.generateKeypair(),
    onSome: (currentKeypair) => Effect.succeed(currentKeypair),
  })

  const publicKeyNtt = yield* toUint16PublicKeyNtt(keypair.publicKeyNtt)
  const packedPublicKey = yield* FalconService.packPublicKey(publicKeyNtt)
  const { address, salt } = yield* StarknetService.computeDeployAddress(packedPublicKey)

  return {
    privateKey: normalizedPrivateKey,
    keypair,
    packedPublicKey,
    address,
    salt,
  } satisfies PreparedAccountDeploy
})

export const deployAccountEffect = Effect.fn(
  "AccountDeployPipeline.deployAccountEffect",
)(function* ({
  address,
  packedPublicKey,
  signer,
  salt,
  requiredBalance,
}: DeployAccountInput) {
  const balance = yield* StarknetService.getBalance(address)

  if (balance < requiredBalance) {
    return yield* Effect.fail(
      new InsufficientFundsError({
        message: "Insufficient STRK balance. Fund the account and try again.",
        address,
        required: requiredBalance.toString(),
      }),
    )
  }

  const deployment = yield* StarknetService.deployAccount(
    packedPublicKey,
    signer,
    salt,
  )

  return deployment
})

import { Config, Effect, Layer } from "effect"
import { RpcProvider, Account, hash, stark } from "starknet"
import type { SignerInterface } from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
  DevnetFetchError,
  TransactionSubmitError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey, DevnetAccount } from "./types"

/** STRK token contract address (same on mainnet and Sepolia) */
export const STRK_TOKEN_ADDRESS =
  "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"

export function parsePrefundedAccounts(raw: unknown[]): DevnetAccount[] {
  return raw
    .filter((item): item is Record<string, string> =>
      typeof item === "object" && item !== null &&
      "address" in item && "private_key" in item
    )
    .map((item) => ({
      address: item.address,
      private_key: item.private_key,
      initial_balance: item.initial_balance ?? "0",
    }))
}

function makeService(rpcUrl: string, classHash: string) {
  const provider = new RpcProvider({ nodeUrl: rpcUrl })

  const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
    function* (packedPk: PackedPublicKey) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      const salt = stark.randomAddress()
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )
      return {
        address: ContractAddress.make(address),
        salt,
      }
    },
  )

  const getBalance = Effect.fn("Starknet.getBalance")(
    function* (address: string) {
      return yield* Effect.tryPromise({
        try: async () => {
          const result = await provider.callContract({
            contractAddress: STRK_TOKEN_ADDRESS,
            entrypoint: "balanceOf",
            calldata: [address],
          })
          return BigInt(result[0])
        },
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const deployAccount = Effect.fn("Starknet.deployAccount")(
    function* (
      packedPk: PackedPublicKey,
      signer: SignerInterface,
      salt: string,
    ) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )

      const account = new Account({ provider, address, signer })

      const result = yield* Effect.tryPromise({
        try: () =>
          account.deployAccount({
            classHash,
            constructorCalldata,
            addressSalt: salt,
            contractAddress: address,
          }),
        catch: (error) =>
          new AccountDeployError({ message: String(error) }),
      })

      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(result.transaction_hash),
        catch: (error) =>
          new AccountDeployError({
            message: `Tx failed: ${error}`,
            txHash: result.transaction_hash,
          }),
      })

      return {
        txHash: TxHash.make(result.transaction_hash),
        address: ContractAddress.make(result.contract_address),
      }
    },
  )

  const waitForTx = Effect.fn("Starknet.waitForTx")(
    function* (txHash: string) {
      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(txHash),
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const fetchPrefundedAccounts = Effect.fn("Starknet.fetchPrefundedAccounts")(
    function* () {
      return yield* Effect.tryPromise({
        try: async () => {
          const baseUrl = rpcUrl.replace(/\/rpc.*$/, "").replace(/\/$/, "")
          const response = await fetch(baseUrl, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              jsonrpc: "2.0",
              id: 1,
              method: "devnet_getPredeployedAccounts",
              params: [],
            }),
          })
          if (!response.ok) {
            throw new Error(`HTTP ${response.status}`)
          }
          const json = await response.json()
          if (json.error) {
            throw new Error(json.error.message ?? JSON.stringify(json.error))
          }
          return parsePrefundedAccounts(json.result as unknown[])
        },
        catch: (error) =>
          new DevnetFetchError({ message: `Failed to fetch prefunded accounts: ${error}` }),
      })
    },
  )

  const sendTransaction = Effect.fn("Starknet.sendTransaction")(
    function* (
      accountAddress: string,
      signer: SignerInterface,
      recipient: string,
      amount: bigint,
    ) {
      const account = new Account({ provider, address: accountAddress, signer })
      return yield* Effect.tryPromise({
        try: async () => {
          const result = await account.execute([
            {
              contractAddress: STRK_TOKEN_ADDRESS,
              entrypoint: "transfer",
              calldata: [recipient, amount.toString(), "0"],
            },
          ])
          await provider.waitForTransaction(result.transaction_hash)
          return { txHash: TxHash.make(result.transaction_hash) }
        },
        catch: (error) =>
          new TransactionSubmitError({ message: String(error) }),
      })
    },
  )

  return {
    computeDeployAddress,
    getBalance,
    deployAccount,
    waitForTx,
    fetchPrefundedAccounts,
    sendTransaction,
    provider,
  }
}

// @ts-ignore — StarknetService.make() intentionally overrides the inherited Effect.Service.make() with a Layer factory
export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      return makeService(rpcUrl, "0x0")
    }),
  },
) {
  /**
   * Custom layer factory for runtime network switching.
   * Use this instead of Default when you need a specific rpcUrl and classHash
   * (e.g., switching between Sepolia and Mainnet at runtime).
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  static make(rpcUrl: string, classHash: string): Layer.Layer<StarknetService> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return Layer.succeed(StarknetService, makeService(rpcUrl, classHash) as any)
  }
}

import { Cause, Exit, type ManagedRuntime, Option } from "effect"
import {
  type Call,
  type InvocationsSignerDetails,
  type DeployAccountSignerDetails,
  type DeclareSignerDetails,
  type Signature,
  type TypedData,
  SignerInterface,
  hash,
  transaction,
  CallData,
  EDAMode,
  type EDataAvailabilityMode,
  typedData as typedDataUtils,
} from "starknet"
import { FalconService } from "./FalconService"
import { TransactionSignError } from "./errors"

function intDAM(dam: EDataAvailabilityMode): EDAMode {
  if (dam === "L1") return EDAMode.L1
  if (dam === "L2") return EDAMode.L2
  throw new Error(`Unknown EDataAvailabilityMode: ${dam}`)
}

export class FalconSigner extends SignerInterface {
  constructor(
    private readonly sk: Uint8Array,
    private readonly pkNtt: Int32Array,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    private readonly runtime: ManagedRuntime.ManagedRuntime<FalconService, any>,
  ) {
    super()
  }

  async getPubKey(): Promise<string> {
    // Falcon public keys are not a single felt — return a placeholder.
    // The actual PK is the 29 packed felt252 slots stored in the contract.
    return "0x0"
  }

  async signMessage(
    typedDataObj: TypedData,
    accountAddress: string,
  ): Promise<Signature> {
    const msgHash = typedDataUtils.getMessageHash(typedDataObj, accountAddress)
    return this._signHash(msgHash)
  }

  async signTransaction(
    transactions: Call[],
    transactionsDetail: InvocationsSignerDetails,
  ): Promise<Signature> {
    const compiledCalldata = transaction.getExecuteCalldata(
      transactions,
      transactionsDetail.cairoVersion,
    )
    const txHash = hash.calculateInvokeTransactionHash({
      ...transactionsDetail,
      senderAddress: transactionsDetail.walletAddress,
      compiledCalldata,
      version: transactionsDetail.version,
      nonceDataAvailabilityMode: intDAM(transactionsDetail.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(transactionsDetail.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  async signDeployAccountTransaction(
    details: DeployAccountSignerDetails,
  ): Promise<Signature> {
    const compiledConstructorCalldata = CallData.compile(
      details.constructorCalldata,
    )
    const txHash = hash.calculateDeployAccountTransactionHash({
      ...details,
      salt: details.addressSalt,
      compiledConstructorCalldata,
      version: details.version,
      nonceDataAvailabilityMode: intDAM(details.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(details.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  async signDeclareTransaction(
    details: DeclareSignerDetails,
  ): Promise<Signature> {
    const txHash = hash.calculateDeclareTransactionHash({
      ...details,
      version: details.version,
      nonceDataAvailabilityMode: intDAM(details.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(details.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  private async _signHash(txHash: string): Promise<string[]> {
    const exit = await this.runtime.runPromiseExit(
      FalconService.signForStarknet(this.sk, txHash, this.pkNtt),
    )

    if (Exit.isSuccess(exit)) {
      return exit.value
    }

    const errOpt = Cause.failureOption(exit.cause)
    const msg = Option.match(errOpt, {
      onNone: () => "Falcon signing failed",
      onSome: (e) => e.message,
    })
    throw new TransactionSignError({ message: msg })
  }
}

import { Effect } from "effect"
import { WasmRuntime } from "./WasmRuntime"
import {
  KeygenError,
  SigningError,
  HintGenerationError,
  PackingError,
  VerificationError,
} from "./errors"
import type {
  FalconKeypair,
  FalconSignatureResult,
  PackedPublicKey,
} from "./types"

// ---------------------------------------------------------------------------
// VK byte deserialization
// ---------------------------------------------------------------------------

/**
 * Deserialize a Falcon-512 verifying key (896 bytes) into 512 NTT-domain
 * coefficients stored as an Int32Array.
 *
 * Format (falcon-rs, PUBLIC_KEY_LEN = 896, no header):
 *   - 512 coefficients x 14 bits each, packed LSB-first
 *
 * Algorithm: maintains a bit-buffer, loading bytes from the input one at a
 * time and extracting 14-bit windows.
 *
 * Throws on invalid input (too few bytes, or any coefficient >= Q=12289).
 */
function parsePublicKeyNttBytes(vkBytes: Uint8Array): Int32Array {
  const Q = 12289
  const N = 512
  const BITS_PER_COEFF = 14
  const DATA_BYTES = (N * BITS_PER_COEFF) / 8 // 896

  if (vkBytes.length < DATA_BYTES) {
    throw new Error(
      `VK too short: expected at least ${DATA_BYTES} bytes, got ${vkBytes.length}`,
    )
  }

  const coeffs = new Int32Array(N)
  const mask = (1 << BITS_PER_COEFF) - 1 // 0x3FFF

  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 0

  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS_PER_COEFF) {
      bitBuffer |= vkBytes[byteIndex++] << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & mask
    bitBuffer >>= BITS_PER_COEFF
    bitsInBuffer -= BITS_PER_COEFF

    if (coeff >= Q) {
      throw new Error(
        `Invalid VK coefficient ${coeff} at index ${i} (must be < ${Q})`,
      )
    }
    coeffs[i] = coeff
  }

  return coeffs
}

// ---------------------------------------------------------------------------
// FalconService
// ---------------------------------------------------------------------------

export class FalconService extends Effect.Service<FalconService>()(
  "FalconService",
  {
    accessors: true,
    // No pre-bundled dependencies: callers must provide WasmRuntime via Layer.
    // This enables unit tests to inject a mock WasmRuntime without the live
    // loader trying to fetch /wasm/falcon_rs.js at import time.
    effect: Effect.gen(function* () {
      const wasm = yield* WasmRuntime

      const generateKeypair = Effect.fn("Falcon.generateKeypair")(
        function* (seed?: Uint8Array) {
          const s =
            seed ?? crypto.getRandomValues(new Uint8Array(32))
          const result = yield* Effect.try({
            try: () => wasm.keygen(s),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          const publicKeyNtt = yield* Effect.try({
            try: () => parsePublicKeyNttBytes(result.vk),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          return {
            secretKey: result.sk,
            verifyingKey: result.vk,
            publicKeyNtt,
          } satisfies FalconKeypair
        },
      )

      const sign = Effect.fn("Falcon.sign")(
        function* (
          secretKey: Uint8Array,
          message: Uint8Array,
        ) {
          const result = yield* Effect.try({
            try: () =>
              wasm.sign(secretKey, message, crypto.getRandomValues(new Uint8Array(40))),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
          return result satisfies FalconSignatureResult
        },
      )

      const verify = Effect.fn("Falcon.verify")(
        function* (
          verifyingKey: Uint8Array,
          message: Uint8Array,
          signature: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.verify(verifyingKey, message, signature),
            catch: (error) =>
              new VerificationError({
                message: String(error),
                step: "verify",
              }),
          })
        },
      )

      const createHint = Effect.fn("Falcon.createHint")(
        function* (
          s1: Int32Array,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.create_verification_hint(s1, pkNtt),
            catch: (error) =>
              new HintGenerationError({ message: String(error) }),
          })
        },
      )

      const packPublicKey = Effect.fn("Falcon.packPublicKey")(
        function* (
          pkNtt: Uint16Array,
        ) {
          const slots = yield* Effect.try({
            try: () => wasm.pack_public_key_wasm(pkNtt),
            catch: (error) =>
              new PackingError({ message: String(error) }),
          })
          return { slots } satisfies PackedPublicKey
        },
      )

      const deserializePublicKeyNtt = Effect.fn(
        "Falcon.deserializePublicKeyNtt",
      )(function* (vkBytes: Uint8Array) {
        return yield* Effect.try({
          try: () => parsePublicKeyNttBytes(vkBytes),
          catch: (error) =>
            new KeygenError({ message: String(error) }),
        })
      })

      const signForStarknet = Effect.fn("Falcon.signForStarknet")(
        function* (
          secretKey: Uint8Array,
          txHash: string,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.sign_for_starknet(secretKey, txHash, pkNtt),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
        },
      )

      return {
        generateKeypair,
        sign,
        verify,
        createHint,
        packPublicKey,
        deserializePublicKeyNtt,
        signForStarknet,
      }
    }),
  },
) {}

import { Context, Effect, Layer } from "effect"
import { WasmLoadError } from "./errors"

// ---------------------------------------------------------------------------
// WasmModule interface
// ---------------------------------------------------------------------------

export interface WasmModule {
  readonly keygen: (seed: Uint8Array) => { sk: Uint8Array; vk: Uint8Array }
  readonly sign: (
    skBytes: Uint8Array,
    message: Uint8Array,
    salt: Uint8Array,
  ) => {
    signature: Uint8Array
    salt: Uint8Array
  }
  readonly verify: (
    vkBytes: Uint8Array,
    message: Uint8Array,
    signature: Uint8Array,
  ) => boolean
  readonly create_verification_hint: (
    s1: Int32Array,
    pkNtt: Int32Array,
  ) => Uint16Array
  readonly pack_public_key_wasm: (pkNtt: Uint16Array) => string[]
  readonly public_key_length: () => number
  readonly salt_length: () => number
  readonly sign_for_starknet: (
    skBytes: Uint8Array,
    txHash: string,
    pkNtt: Int32Array,
  ) => string[]
}

// ---------------------------------------------------------------------------
// Runtime type validation — no `as any` or `as unknown as WasmModule`
// ---------------------------------------------------------------------------

/**
 * Runtime guard that checks every method in the WasmModule interface exists
 * and is a function. Returns true only when all seven methods are present.
 *
 * This replaces the unsafe `as unknown as WasmModule` cast that was used in
 * the original implementation.
 *
 * Validation scope: checks that each required key is present and is a
 * function. Function arity and return types cannot be checked without
 * invoking the function (which would have side effects), so only presence
 * and kind are validated here.
 *
 * No type assertions are used: after the null/typeof guard, TypeScript
 * narrows `mod` to `object`, which satisfies `Reflect.get`'s `target:
 * object` parameter — property access is type-safe without any cast.
 */
export function isValidWasmModule(mod: unknown): mod is WasmModule {
  if (mod === null || typeof mod !== "object") return false
  // TypeScript narrows `mod` to `object` here — no type assertion needed.
  // Reflect.get accepts `object` as its first argument directly.
  const methods = [
    "keygen",
    "sign",
    "verify",
    "create_verification_hint",
    "pack_public_key_wasm",
    "public_key_length",
    "salt_length",
    "sign_for_starknet",
  ] as const
  return methods.every((method) => typeof Reflect.get(mod, method) === "function")
}

// ---------------------------------------------------------------------------
// Context.Tag — WasmRuntime service tag
// ---------------------------------------------------------------------------

export class WasmRuntime extends Context.Tag("WasmRuntime")<
  WasmRuntime,
  WasmModule
>() {}

// ---------------------------------------------------------------------------
// Internal load function — uses Effect.fn for automatic span tracing
// ---------------------------------------------------------------------------

const loadWasmModule = Effect.fn("WasmRuntime.load")(function* () {
  const mod = yield* Effect.tryPromise({
    try: async () => {
      // Dynamic import of the WASM JS glue generated by wasm-pack.
      // The `/* webpackIgnore: true */` comment prevents bundlers from
      // trying to resolve this path at build time.
      const modulePath = "/wasm/falcon_rs.js"
      const imported = await import(
        /* webpackIgnore: true */
        modulePath
      )
      // Run the WASM initializer (wasm-pack generates a default export
      // that downloads and instantiates the .wasm binary).
      await imported.default()
      return imported
    },
    catch: (error) =>
      new WasmLoadError({
        message: `Failed to load WASM module: ${String(error)}`,
      }),
  })

  // Runtime validation — replaces unsafe `as unknown as WasmModule`
  if (!isValidWasmModule(mod)) {
    return yield* Effect.fail(
      new WasmLoadError({
        message:
          "WASM module is missing required methods. Expected: keygen, sign, verify, " +
          "create_verification_hint, pack_public_key_wasm, public_key_length, salt_length, sign_for_starknet.",
      }),
    )
  }

  yield* Effect.log("WasmRuntime loaded successfully")
  return mod
})

// ---------------------------------------------------------------------------
// WasmRuntimeLive — Layer that loads and validates the WASM module
//
// Effect's Layer memoization guarantees this effect runs at most once when
// the Layer is provided to the application. There is no mutable global state
// (`let cachedModule`); the singleton guarantee comes from Layer itself.
// ---------------------------------------------------------------------------

export const WasmRuntimeLive = Layer.effect(WasmRuntime, loadWasmModule())

import { dirname } from "path"
import { fileURLToPath } from "url"

const __dirname = dirname(fileURLToPath(import.meta.url))

/** @type {import('next').NextConfig} */
const nextConfig = {
  turbopack: {
    root: __dirname,
  },
  webpack(config) {
    config.experiments = { ...config.experiments, asyncWebAssembly: true }
    config.output.webassemblyModuleFilename = "static/wasm/[modulehash].wasm"
    return config
  },
}

export default nextConfig

